import {Request, Response} from "express";
import {UserService} from "./service";

export const getUser = async (req: Request, res: Response) => {
    try {
        const user = await UserService.getUser()
        res.status(200)
            .json({
                user
            })
    }catch (e) {
        throw res.status(500)
            .json({
                error: e?.toString()
            })
    }
}
